// File an insurance claim (FNOL) step component — generated by flowforge JTBD generator.
// Re-run the generator to regenerate; do not edit by hand.
import * as React from "react";
import { FormRenderer, type FormErrors, type FormValues, type RendererFormSpec } from "@flowforge/renderer";

import formSpec from "../../../../workflows/claim_intake/form_spec.json";

export interface ClaimIntakeStepProps {
	instanceId: string;
	state: string;
	onEvent: (event: string, payload?: Record<string, unknown>) => Promise<void> | void;
	/** Optional context map for show_if conditional fields (reuses the engine's `var` operator). */
	context?: Record<string, unknown>;
}

interface FieldMeta {
	id: string;
	label: string;
	required: boolean;
	pii: boolean;
}

const FIELDS: ReadonlyArray<FieldMeta> = [
	{ id: "claimant_name", label: "Claimant full name", required: true, pii: true },
	{ id: "policy_number", label: "Policy number", required: true, pii: false },
	{ id: "loss_date", label: "Date of loss", required: true, pii: false },
	{ id: "loss_amount", label: "Estimated loss amount", required: true, pii: false },
	{ id: "loss_description", label: "Description of loss", required: true, pii: false },
	{ id: "contact_email", label: "Contact email", required: true, pii: true },
	{ id: "contact_phone", label: "Contact phone", required: false, pii: true },
];

const SPEC = formSpec as unknown as RendererFormSpec;
const PII_FIELD_IDS: ReadonlyArray<string> = FIELDS.filter((f) => f.pii).map((f) => f.id);

/**
 * Real form step for the claim_intake workflow. Wraps `@flowforge/renderer`'s
 * FormRenderer over the generated form_spec.json. Validators are derived from
 * data_capture.validation; show_if uses the engine's whitelisted `var` operator
 * (no new operators introduced).
 *
 * PII fields default to a masked text node with an eye-toggle, keeping screen
 * leaks to a minimum during shoulder-surfing demos. Inline errors link via
 * `aria-describedby` so assistive tech surfaces them next to the offending field.
 */
export function ClaimIntakeStep(props: ClaimIntakeStepProps): React.ReactElement {
	const [busy, setBusy] = React.useState(false);
	const [values, setValues] = React.useState<FormValues>({});
	const [errors, setErrors] = React.useState<FormErrors>({});
	const [revealedPii, setRevealedPii] = React.useState<ReadonlyArray<string>>([]);

	const togglePii = React.useCallback((id: string) => {
		setRevealedPii((prev) => (prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id]));
	}, []);

	const fire = React.useCallback(
		async (event: string, payload: Record<string, unknown>) => {
			if (busy) return;
			setBusy(true);
			try {
				await props.onEvent(event, payload);
			} finally {
				setBusy(false);
			}
		},
		[busy, props],
	);

	const handleSubmit = React.useCallback(
		async (submitted: FormValues) => {
			await fire("submit", submitted);
		},
		[fire],
	);

	return (
		<section data-testid="claim_intake-step" aria-labelledby="claim_intake-step-title">
			<header>
				<h2 id="claim_intake-step-title">File an insurance claim (FNOL)</h2>
				<p>State: <code>{props.state}</code></p>
				<p>Instance: <code>{props.instanceId}</code></p>
			</header>
			<FormRenderer
				spec={SPEC}
				values={values}
				onChange={setValues}
				onSubmit={handleSubmit}
				onValidate={setErrors}
				validateOn="blur"
				disabled={busy}
				submitLabel={busy ? "Submitting…" : "Submit"}
				data-testid="claim_intake-form"
			/>
			{PII_FIELD_IDS.length > 0 ? (
				<aside aria-label="PII fields">
					<h3>Sensitive fields</h3>
					<ul>
						{PII_FIELD_IDS.map((id) => {
							const meta = FIELDS.find((f) => f.id === id)!;
							const revealed = revealedPii.includes(id);
							const raw = values[id];
							const display = revealed ? (raw == null ? "" : String(raw)) : "••••••";
							const errorId = errors[id] ? `${id}-error` : undefined;
							return (
								<li key={id}>
									<span>{meta.label}: </span>
									<span aria-describedby={errorId} data-pii-revealed={revealed ? "true" : "false"}>
										{display}
									</span>
									<button type="button" onClick={() => togglePii(id)} aria-pressed={revealed}>
										{revealed ? "Hide" : "Show"}
									</button>
									{errorId ? (
										<span id={errorId} role="alert">
											{errors[id]}
										</span>
									) : null}
								</li>
							);
						})}
					</ul>
				</aside>
			) : null}
			<footer>
				<button type="button" disabled={busy} onClick={() => fire("approve", {})}>
					Approve
				</button>
			</footer>
		</section>
	);
}
